// Map form category labels to LocationIQ / OSM PoI tags
// LocationIQ Nearby supports both single-word tags and key=value pairs
const categoryInput = $input.first().json['Business Category'];
const city          = $input.first().json['City'];
const radius        = $input.first().json['Search Radius (meters)'] || '5000';

const tagMap = {
  'Hotels':          'hotel',
  'Guest Houses':    'guest_house',
  'Restaurants':     'restaurant',
  'Cafes':           'cafe',
  'Bars':            'bar',
  'Clinics':         'clinic',
  'Hospitals':       'hospital',
  'Pharmacies':      'pharmacy',
  'Salons':          'beauty',
  'Supermarkets':    'supermarket',
  'Banks':           'bank',
  'Schools':         'school',
  'Tour Operators':  'travel_agent'
};

const tag = tagMap[categoryInput] || categoryInput.toLowerCase();

return [{
  json: {
    category:  categoryInput,
    city:      city,
    tag:       tag,
    radius:    radius,
    token:     'pk.c9672dfbd60d64e1282081cb90e4222d'
  }
}];

// Extract lat/lon from geocoding result and pass forward
const geo      = $input.first().json;
const inputs   = $('Map Category to LocationIQ Tag').first().json;

if (!geo || !geo[0]) {
  throw new Error('Could not geocode city: ' + inputs.city + '. Check the city name and try again.');
}

const lat = geo[0].lat;
const lon = geo[0].lon;
const displayName = geo[0].display_name;

return [{
  json: {
    category:     inputs.category,
    city:         inputs.city,
    tag:          inputs.tag,
    radius:       inputs.radius,
    token:        inputs.token,
    lat:          lat,
    lon:          lon,
    display_name: displayName
  }
}];

// Parse LocationIQ Nearby PoI results into clean business records
// LocationIQ returns: place_id, osm_id, lat, lon, display_name, address{}, namedetails{}
const results  = $input.first().json;
const inputs   = $('Extract Coordinates').first().json;

if (!results || !Array.isArray(results) || results.length === 0) {
  return [{
    json: {
      error:    'No businesses found by LocationIQ for: ' + inputs.category + ' in ' + inputs.city,
      category: inputs.category,
      city:     inputs.city
    }
  }];
}

return results.map(place => {
  const addr = place.address || {};

  // Build readable address from LocationIQ address object
  const addressParts = [
    addr.road || addr.pedestrian,
    addr.suburb || addr.neighbourhood,
    addr.city || addr.town || addr.village || inputs.city,
    addr.country
  ].filter(Boolean);

  // LocationIQ gives us the name directly
  const name = place.name || place.namedetails?.name || place.display_name?.split(',')[0] || 'Unknown';

  // Build Google Maps search link using name + city
  const mapsSearch = 'https://www.google.com/maps/search/' + encodeURIComponent(name + ' ' + inputs.city);

  return {
    json: {
      place_id:       place.place_id,
      osm_id:         place.osm_id,
      osm_type:       place.osm_type,
      name:           name,
      category:       inputs.category,
      city:           inputs.city,
      address:        addressParts.join(', ') || inputs.city,
      lat:            place.lat,
      lon:            place.lon,
      // LocationIQ may return website/phone if present in OSM data
      website:        place.address?.website || null,
      phone:          place.address?.phone   || null,
      has_website:    !!(place.address?.website),
      has_phone:      !!(place.address?.phone),
      // Direct links
      osm_url:        'https://www.openstreetmap.org/' + (place.osm_type || 'node') + '/' + place.osm_id,
      maps_search_url: mapsSearch,
      token:          inputs.token
    }
  };
});

// Merge LocationIQ reverse geocode enrichment with the base business record
// extratags contains: website, phone, email, opening_hours, contact:* etc.
const detail  = $input.first().json;
const biz     = $('Process in Batches').first().json;
const extra   = detail.extratags || {};
const addr    = detail.address   || {};

// Extract all possible website and contact fields
const website   = extra.website          || extra['contact:website']  || extra.url          || biz.website  || null;
const phone     = extra.phone            || extra['contact:phone']    || extra['contact:mobile'] || biz.phone || null;
const email     = extra.email            || extra['contact:email']    || null;
const facebook  = extra['contact:facebook']  || extra.facebook        || null;
const instagram = extra['contact:instagram'] || extra.instagram       || null;
const twitter   = extra['contact:twitter']   || extra.twitter         || null;
const whatsapp  = extra['contact:whatsapp']  || null;
const hours     = extra.opening_hours    || null;

// Refined address from reverse geocode
const refinedAddress = [
  addr.road || addr.pedestrian,
  addr.suburb || addr.neighbourhood || addr.quarter,
  addr.city || addr.town || biz.city
].filter(Boolean).join(', ') || biz.address;

return [{
  json: {
    // Carry forward all base fields
    ...biz,
    // Override with enriched data
    address:        refinedAddress,
    website:        website,
    has_website:    !!website,
    phone:          phone,
    has_phone:      !!phone,
    email:          email,
    facebook_direct: facebook,
    instagram_direct: instagram,
    twitter_direct: twitter,
    whatsapp_direct: whatsapp,
    opening_hours:  hours,
    has_hours:      !!hours,
    // Store all raw extra tags for AI context
    extra_tags_raw: JSON.stringify(extra).substring(0, 300)
  }
}];

const item       = $input.first();
const statusCode = item.json.statusCode || item.json.status || 0;
const isLive     = statusCode >= 200 && statusCode < 400;

return [{
  json: {
    website_live:        isLive,
    website_status_code: statusCode,
    website_checked:     true
  }
}];

