const resp = $input.first().json;
let ai = {};
try {
  const raw     = resp.choices?.[0]?.message?.content || '{}';
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  ai = JSON.parse(cleaned);
} catch (e) {
  ai = {
    facebook_url: null, instagram_url: null, twitter_url: null, linkedin_url: null,
    tripadvisor_listed: false, booking_com_listed: false, airbnb_listed: false,
    whatsapp_business: false, has_google_business: false,
    online_score: 0, missing_channels: [],
    weakness: 'AI analysis failed — manual review needed',
    opportunity: 'Manual review needed',
    priority: 'medium'
  };
}
return [{ json: ai }];

const items = $input.all();
const biz   = $('Extract All Business Details').first().json;

// Website live check
let websiteLive = false, statusCode = 0;
try {
  const ws = items.find(i => i.json.website_checked);
  websiteLive = ws?.json?.website_live || false;
  statusCode  = ws?.json?.website_status_code || 0;
} catch(e) {}

// AI result
let ai = {};
try {
  const aiItem = items.find(i => i.json.hasOwnProperty('online_score'));
  ai = aiItem?.json || {};
} catch(e) {}

// ---- SCORING (0–100) ----
let score = 0;

// LocationIQ / Map data signals — what we KNOW for certain
if (biz.has_website)                              score += 15; // Has website in map data
if (biz.has_website && websiteLive)               score += 10; // Website is actually live
if (biz.has_phone)                                score += 5;  // Has phone number
if (biz.has_hours)                                score += 5;  // Has opening hours
if (biz.facebook_direct || ai.facebook_url)       score += 7;  // Facebook
if (biz.instagram_direct || ai.instagram_url)     score += 7;  // Instagram

// AI-discovered platforms
if (ai.twitter_url)                               score += 3;  // Twitter/X
if (ai.linkedin_url)                              score += 3;  // LinkedIn
if (ai.whatsapp_business || biz.whatsapp_direct)  score += 5;  // WhatsApp Business
if (ai.has_google_business)                       score += 15; // Google Business Profile
if (ai.tripadvisor_listed)                        score += 10; // TripAdvisor
if (ai.booking_com_listed)                        score += 10; // Booking.com
if (ai.airbnb_listed)                             score += 5;  // Airbnb

score = Math.min(100, score);

let tier, tier_emoji;
if      (score >= 70) { tier = 'Strong';   tier_emoji = '🟢'; }
else if (score >= 40) { tier = 'Moderate'; tier_emoji = '🟡'; }
else                  { tier = 'Weak';     tier_emoji = '🔴'; }

// Prefer map-sourced data over AI guesses where both exist
const facebook  = biz.facebook_direct  || ai.facebook_url  || 'Not found';
const instagram = biz.instagram_direct || ai.instagram_url || 'Not found';
const twitter   = biz.twitter_direct   || ai.twitter_url   || 'Not found';
const whatsapp  = biz.whatsapp_direct  || (ai.whatsapp_business ? 'Active' : 'Not found');

return [{
  json: {
    business_name:      biz.name,
    category:           biz.category,
    city:               biz.city,
    address:            biz.address,
    phone:              biz.phone        || 'Not listed',
    email:              biz.email        || 'Not listed',
    website:            biz.website      || 'Not listed',
    has_website:        biz.has_website,
    website_live:       websiteLive,
    opening_hours:      biz.opening_hours|| 'Not listed',
    facebook:           facebook,
    instagram:          instagram,
    twitter:            twitter,
    linkedin:           ai.linkedin_url  || 'Not found',
    whatsapp:           whatsapp,
    tripadvisor:        ai.tripadvisor_listed  || false,
    booking_com:        ai.booking_com_listed  || false,
    airbnb:             ai.airbnb_listed       || false,
    google_business:    ai.has_google_business || false,
    online_score:       score,
    full_tier:          tier_emoji + ' ' + tier,
    tier:               tier,
    priority:           ai.priority            || 'medium',
    missing_channels:   (ai.missing_channels || []).join(', ') || 'None identified',
    weakness:           ai.weakness            || 'Unknown',
    opportunity:        ai.opportunity         || 'Unknown',
    maps_search_url:    biz.maps_search_url,
    osm_url:            biz.osm_url,
    outreach_message:   '',
    audited_date:       new Date().toLocaleDateString('en-GB'),
    audited_at:         new Date().toISOString()
  }
}];

